<?php
session_start();
require_once '../includes/db_config.php';
if (!isset($_SESSION['user_id']) || $_SESSION['role'] !== 'admin') { header('Location: ../login.php'); exit; }
$pdo = getDBConnection();
$message = ''; $messageType = '';
if (isset($_GET['delete'])) { $stmt = $pdo->prepare("UPDATE products SET active = 0 WHERE product_id = :id"); $stmt->execute([':id' => (int)$_GET['delete']]); $message = 'Product deleted successfully.'; $messageType = 'success'; }
if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    $name = trim($_POST['name'] ?? ''); $categoryId = (int)($_POST['category_id'] ?? 0); $price = (float)($_POST['price'] ?? 0); $salePrice = !empty($_POST['sale_price']) ? (float)$_POST['sale_price'] : null; $description = trim($_POST['description'] ?? ''); $brand = trim($_POST['brand'] ?? 'Glamour Haven'); $stock = (int)($_POST['stock'] ?? 0); $featured = isset($_POST['featured']) ? 1 : 0; $image = trim($_POST['image'] ?? 'lipstick_red.jpg');
    if (isset($_POST['product_id']) && $_POST['product_id'] > 0) { $stmt = $pdo->prepare("UPDATE products SET name=:name, category_id=:cid, price=:price, sale_price=:sp, description=:desc, brand=:brand, stock=:stock, featured=:feat, image=:img WHERE product_id=:pid"); $stmt->execute([':name'=>$name,':cid'=>$categoryId,':price'=>$price,':sp'=>$salePrice,':desc'=>$description,':brand'=>$brand,':stock'=>$stock,':feat'=>$featured,':img'=>$image,':pid'=>(int)$_POST['product_id']]); $message = 'Product updated successfully!'; }
    else { $stmt = $pdo->prepare("INSERT INTO products (name, category_id, price, sale_price, description, brand, stock, featured, image, active) VALUES (:name, :cid, :price, :sp, :desc, :brand, :stock, :feat, :img, 1)"); $stmt->execute([':name'=>$name,':cid'=>$categoryId,':price'=>$price,':sp'=>$salePrice,':desc'=>$description,':brand'=>$brand,':stock'=>$stock,':feat'=>$featured,':img'=>$image]); $message = 'Product added successfully!'; }
    $messageType = 'success';
}
$products = $pdo->query("SELECT p.*, c.name as category_name FROM products p JOIN categories c ON p.category_id = c.category_id WHERE p.active = 1 ORDER BY p.created_at DESC")->fetchAll();
$categories = $pdo->query("SELECT * FROM categories ORDER BY name")->fetchAll();
$editProduct = null;
if (isset($_GET['edit'])) { $stmt = $pdo->prepare("SELECT * FROM products WHERE product_id = :id"); $stmt->execute([':id' => (int)$_GET['edit']]); $editProduct = $stmt->fetch(); }
?>
