        <?php if ($message): ?><div class="alert alert-<?php echo $messageType; ?> alert-dismissible fade show"><?php echo $message; ?><button type="button" class="btn-close" data-bs-dismiss="alert"></button></div><?php endif; ?>
        <div class="card border-0 shadow-sm"><div class="card-body p-0"><div class="table-responsive"><table class="table table-hover mb-0"><thead class="table-light"><tr><th>Image</th><th>Name</th><th>Category</th><th>Price</th><th>Sale</th><th>Stock</th><th>Featured</th><th>Actions</th></tr></thead><tbody>
        <?php foreach ($products as $p): ?>
        <tr><td><img src="../images/<?php echo htmlspecialchars($p['image']); ?>" width="50" height="50" style="object-fit:cover; border-radius:5px;"></td><td><strong><?php echo htmlspecialchars($p['name']); ?></strong><br><small class="text-muted"><?php echo htmlspecialchars($p['brand']); ?></small></td><td><?php echo htmlspecialchars($p['category_name']); ?></td><td>$<?php echo number_format($p['price'], 2); ?></td><td><?php echo $p['sale_price'] ? '$' . number_format($p['sale_price'], 2) : '-'; ?></td><td><?php if ($p['stock'] < 10): ?><span class="text-danger fw-bold"><?php echo $p['stock']; ?></span><?php else: echo $p['stock']; endif; ?></td><td><?php echo $p['featured'] ? '<i class="bi bi-star-fill" style="color:var(--primary);"></i>' : '-'; ?></td><td><a href="manage_products.php?edit=<?php echo $p['product_id']; ?>" class="btn btn-sm btn-outline-primary me-1"><i class="bi bi-pencil"></i></a><a href="manage_products.php?delete=<?php echo $p['product_id']; ?>" class="btn btn-sm btn-outline-danger confirm-delete"><i class="bi bi-trash"></i></a></td></tr>
        <?php endforeach; ?>
        </tbody></table></div></div></div>
    </div>
</div></div>
<div class="modal fade" id="productModal" tabindex="-1"><div class="modal-dialog modal-lg"><div class="modal-content"><form method="POST"><div class="modal-header"><h5 class="modal-title" id="modalTitle">Add New Product</h5><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><input type="hidden" name="product_id" id="productId" value="0"><div class="row g-3"><div class="col-md-8"><label class="form-label">Product Name *</label><input type="text" class="form-control" name="name" id="prodName" required></div><div class="col-md-4"><label class="form-label">Category *</label><select name="category_id" id="prodCat" class="form-select" required><?php foreach ($categories as $cat): ?><option value="<?php echo $cat['category_id']; ?>"><?php echo htmlspecialchars($cat['name']); ?></option><?php endforeach; ?></select></div><div class="col-md-4"><label class="form-label">Price ($) *</label><input type="number" class="form-control" name="price" id="prodPrice" step="0.01" min="0" required></div><div class="col-md-4"><label class="form-label">Sale Price ($)</label><input type="number" class="form-control" name="sale_price" id="prodSale" step="0.01" min="0"></div><div class="col-md-4"><label class="form-label">Stock *</label><input type="number" class="form-control" name="stock" id="prodStock" min="0" required></div><div class="col-md-6"><label class="form-label">Brand</label><input type="text" class="form-control" name="brand" id="prodBrand" value="Glamour Haven"></div><div class="col-md-6"><label class="form-label">Image Filename</label><input type="text" class="form-control" name="image" id="prodImage" value="lipstick_red.jpg"><small class="text-muted">Place image in /images folder</small></div><div class="col-12"><label class="form-label">Description</label><textarea class="form-control" name="description" id="prodDesc" rows="3"></textarea></div><div class="col-12"><div class="form-check"><input class="form-check-input" type="checkbox" name="featured" id="prodFeatured"><label class="form-check-label" for="prodFeatured">Featured Product</label></div></div></div></div><div class="modal-footer"><button type="button" class="btn btn-secondary" data-bs-dismiss="modal">Cancel</button><button type="submit" class="btn btn-glamour">Save Product</button></div></form></div></div></div>
