<script>
function resetForm(){document.getElementById('modalTitle').textContent='Add New Product';document.getElementById('productId').value='0';document.getElementById('prodName').value='';document.getElementById('prodPrice').value='';document.getElementById('prodSale').value='';document.getElementById('prodStock').value='';document.getElementById('prodBrand').value='Glamour Haven';document.getElementById('prodImage').value='lipstick_red.jpg';document.getElementById('prodDesc').value='';document.getElementById('prodFeatured').checked=false;}
<?php if ($editProduct): ?>
window.addEventListener('DOMContentLoaded',function(){document.getElementById('modalTitle').textContent='Edit Product';document.getElementById('productId').value='<?php echo $editProduct['product_id']; ?>';document.getElementById('prodName').value='<?php echo addslashes($editProduct['name']); ?>';document.getElementById('prodCat').value='<?php echo $editProduct['category_id']; ?>';document.getElementById('prodPrice').value='<?php echo $editProduct['price']; ?>';document.getElementById('prodSale').value='<?php echo $editProduct['sale_price'] ?? ''; ?>';document.getElementById('prodStock').value='<?php echo $editProduct['stock']; ?>';document.getElementById('prodBrand').value='<?php echo addslashes($editProduct['brand']); ?>';document.getElementById('prodImage').value='<?php echo addslashes($editProduct['image']); ?>';document.getElementById('prodDesc').value=`<?php echo addslashes($editProduct['description']); ?>`;document.getElementById('prodFeatured').checked=<?php echo $editProduct['featured'] ? 'true' : 'false'; ?>;new bootstrap.Modal(document.getElementById('productModal')).show();});
<?php endif; ?>
</script></body></html>
